requirements.capl_script:
/* REQ: IC-REQ-01 */
variables
{
  message 640 IC_Driver_Command msgICDriverCmd;
}
on start
{
  // Initialize message payload to safe state
  int i;
  for (i = 0; i < 4; i++)
  {
    msgICDriverCmd.byte(i) = 0;
  }
  msgICDriverCmd.dlc = 4;
  msgICDriverCmd.IC_Horn_Request = 0;
  output(msgICDriverCmd);
}
on sysvar_update sysvar::IC::HornSwitch
{
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 4; i++)
  {
    msgICDriverCmd.byte(i) = 0;
  }
  msgICDriverCmd.dlc = 4;
  msgICDriverCmd.IC_Horn_Request = @sysvar::IC::HornSwitch;
  output(msgICDriverCmd);
}

/* REQ: IC-REQ-02 */
variables
{
  message 640 IC_Driver_Command msgIC;
}
void sendTurnCommand(int value)
{
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 4; i++)
  {
    msgIC.byte(i) = 0;
  }
  msgIC.dlc = 4;
  msgIC.IC_Turn_Command = value;
  output(msgIC);
}
on key '0' { sendTurnCommand(0); }
on key '1' { sendTurnCommand(1); }
on key '2' { sendTurnCommand(2); }
on key '3' { sendTurnCommand(3); }

/* REQ: IC-REQ-03 */
variables
{
  message IC_Driver_Command icMsg;
  int highBeamState = 0;
}
on start
{
  // Initialize message payload to safe state
  int i;
  for (i = 0; i < 4; i++)
  {
    icMsg.byte(i) = 0;
  }
  icMsg.dlc = 4;
  icMsg.IC_HighBeam_Request = 0;
  output(icMsg);
}
on key 'h'
{
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 4; i++)
  {
    icMsg.byte(i) = 0;
  }
  icMsg.dlc = 4;
  highBeamState = 1;
  icMsg.IC_HighBeam_Request = 1;
  output(icMsg);
}
on key 'l'
{
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 4; i++)
  {
    icMsg.byte(i) = 0;
  }
  icMsg.dlc = 4;
  highBeamState = 0;
  icMsg.IC_HighBeam_Request = 0;
  output(icMsg);
}

variables
{
  msTimer absTxTimer;
  float baseSpeed = 40.0;
  float flSpeed;
  float frSpeed;
  float rlSpeed;
  float rrSpeed;
}

on start
{
  setTimer(absTxTimer, 100);
}

on timer absTxTimer
{
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    ABS_Wheel_Info.byte(i) = 0;
  }
  ABS_Wheel_Info.dlc = 8;
  flSpeed = limit(baseSpeed + random(-5, 5) * 0.1, 0.0, 250.0);
  frSpeed = limit(baseSpeed + random(-5, 5) * 0.1, 0.0, 250.0);
  rlSpeed = limit(baseSpeed + random(-5, 5) * 0.1, 0.0, 250.0);
  rrSpeed = limit(baseSpeed + random(-5, 5) * 0.1, 0.0, 250.0);

  ABS_Wheel_Info.ABS_Wheel_FL_Speed = flSpeed;
  ABS_Wheel_Info.ABS_Wheel_FR_Speed = frSpeed;
  ABS_Wheel_Info.ABS_Wheel_RL_Speed = rlSpeed;
  ABS_Wheel_Info.ABS_Wheel_RR_Speed = rrSpeed;

  output(ABS_Wheel_Info);
  setTimer(absTxTimer, 100);
}

on key '+'
{
  baseSpeed += 5;
  if (baseSpeed > 250) baseSpeed = 250;
}

on key '-'
{
  baseSpeed -= 5;
  if (baseSpeed < 0) baseSpeed = 0;
}

variables
{
  msTimer wheelTimer;
  message 700 ABS_Wheel_Info msgWheel;
  float baseSpeed = 0.0;
  float accel = 0.2;
  int direction = 1;
}

on start
{
  // Initialize message payload to safe state
  int i;
  for (i = 0; i < 8; i++)
  {
    msgWheel.byte(i) = 0;
  }
  msgWheel.dlc = 8;
  setTimer(wheelTimer, 20);
}

on timer wheelTimer
{
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    msgWheel.byte(i) = 0;
  }
  msgWheel.dlc = 8;
  baseSpeed += accel * direction;
  if (baseSpeed > 120) direction = -1;
  if (baseSpeed < 0) direction = 1;

  msgWheel.ABS_Wheel_FL_Speed = baseSpeed + 0.2;
  msgWheel.ABS_Wheel_FR_Speed = baseSpeed - 0.1;
  msgWheel.ABS_Wheel_RL_Speed = baseSpeed + 0.0;
  msgWheel.ABS_Wheel_RR_Speed = baseSpeed - 0.2;

  output(msgWheel);
  setTimer(wheelTimer, 20);
}

variables
{
  message BCM_Body_State msgBCM;
  message IC_Driver_Command msgIC;
  message GW_System_Overview msgGW;
  msTimer gwTxTimer;
}

on start
{
  // Initialize message payload to safe state
  int i;
  for (i = 0; i < 8; i++)
  {
    msgGW.byte(i) = 0;
  }
  msgGW.dlc = 8;
  msgGW.GWS_Any_Door_Open = 0;
  msgGW.GWS_Horn_Active = 0;
  msgGW.GWS_Indicator_State = 0;
  msgGW.GWS_Any_Light_On = 0;
  setTimer(gwTxTimer, 100);
}

on timer gwTxTimer
{
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    msgGW.byte(i) = 0;
  }
  msgGW.dlc = 8;
  output(msgGW);
  setTimer(gwTxTimer, 100);
}

on message BCM_Body_State
{
  msgBCM = this;
  msgGW.GWS_Any_Door_Open = (msgBCM.Bdy_Door_Front_Left || msgBCM.Bdy_Door_Front_Right || msgBCM.Bdy_Door_Rear_Left || msgBCM.Bdy_Door_Rear_Right || msgBCM.Bdy_Tailgate_Open);
  msgGW.GWS_Any_Light_On = (msgBCM.Bdy_Hazard_Active || msgBCM.Bdy_Parking_Lamp);
}

on message IC_Driver_Command
{
  msgIC = this;
  msgGW.GWS_Horn_Active = msgIC.IC_Horn_Request;
  msgGW.GWS_Indicator_State = msgIC.IC_Turn_Command;
}

variables
{
  msTimer powertrainTimer;
  message 520 ECM_Powertrain_Data;
  message 560 TCM_Gear_Status;
  message 700 ABS_Wheel_Info;
  float vehicleSpeed = 0.0;
  int engineSpeed = 800;
  int gear = 1;
}

on start
{
  setTimer(powertrainTimer, 100);
}

on timer powertrainTimer
{
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    ECM_Powertrain_Data.byte(i) = 0;
    TCM_Gear_Status.byte(i) = 0;
    ABS_Wheel_Info.byte(i) = 0;
  }
  ECM_Powertrain_Data.dlc = 8;
  TCM_Gear_Status.dlc = 8;
  ABS_Wheel_Info.dlc = 8;
  vehicleSpeed += 0.5;
  if (vehicleSpeed > 120) vehicleSpeed = 0;
  engineSpeed = 800 + (int)(vehicleSpeed * 40);
  gear = (int)(vehicleSpeed / 20) + 1;

  ECM_Powertrain_Data.ECM_Vehicle_Speed = vehicleSpeed;
  ECM_Powertrain_Data.ECM_Engine_Speed = engineSpeed;
  output(ECM_Powertrain_Data);

  TCM_Gear_Status.TCM_Current_Gear = (gear > 6) ? 6 : gear;
  output(TCM_Gear_Status);

  ABS_Wheel_Info.ABS_Wheel_FL_Speed = vehicleSpeed;
  output(ABS_Wheel_Info);

  setTimer(powertrainTimer, 100);
}

variables
{
  message BCM_Body_State bcmMsg;
  message GW_System_Overview gwMsg;
  int anyDoorOpen;
}

on message BCM_Body_State
{
  bcmMsg = this;
  anyDoorOpen = (bcmMsg.Bdy_Door_Front_Left || bcmMsg.Bdy_Door_Front_Right || bcmMsg.Bdy_Door_Rear_Left || bcmMsg.Bdy_Door_Rear_Right);
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    gwMsg.byte(i) = 0;
  }
  gwMsg.dlc = 8;
  gwMsg.GWS_Any_Door_Open = anyDoorOpen;
  output(gwMsg);
}

variables
{
  message GW_System_Overview gwMsg;
  msTimer gwCyclicTimer;
  int hornState = 0;
}

on start
{
  // Initialize message payload to safe state
  int i;
  for (i = 0; i < 8; i++)
  {
    gwMsg.byte(i) = 0;
  }
  gwMsg.dlc = 8;
  gwMsg.GWS_Horn_Active = 0;
  setTimer(gwCyclicTimer, 100);
}

on message IC_Driver_Command
{
  if (this.IC_Horn_Request != hornState)
  {
    hornState = this.IC_Horn_Request;
    // Reset payload before setting signals
    int i;
    for (i = 0; i < 8; i++)
    {
      gwMsg.byte(i) = 0;
    }
    gwMsg.dlc = 8;
    gwMsg.GWS_Horn_Active = hornState;
    output(gwMsg);
  }
}

on timer gwCyclicTimer
{
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    gwMsg.byte(i) = 0;
  }
  gwMsg.dlc = 8;
  output(gwMsg);
  setTimer(gwCyclicTimer, 100);
}

/* REQ: GW-REQ-05 */
variables
{
  msTimer gwTxTimer;
  float ecmVehSpeed = -1;
  float ecmEngSpeed = -1;
  float wheelFL = -1; float wheelFR = -1; float wheelRL = -1; float wheelRR = -1;
  float derivedSpeed = 0;
}

on start
{
  setTimer(gwTxTimer, 100);
}

on message ECM_Powertrain_Data
{
  ecmVehSpeed = this.ECM_Vehicle_Speed;
  ecmEngSpeed = this.ECM_Engine_Speed;
}

on message ABS_Wheel_Info
{
  wheelFL = this.ABS_Wheel_FL_Speed; wheelFR = this.ABS_Wheel_FR_Speed;
  wheelRL = this.ABS_Wheel_RL_Speed; wheelRR = this.ABS_Wheel_RR_Speed;
}

on timer gwTxTimer
{
  message GW_System_Overview gwMsg;
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    gwMsg.byte(i) = 0;
  }
  gwMsg.dlc = 8;
  int validWheels = 0; float sum = 0;
  if (wheelFL >= 0) { sum += wheelFL; validWheels++; }
  if (wheelFR >= 0) { sum += wheelFR; validWheels++; }
  if (wheelRL >= 0) { sum += wheelRL; validWheels++; }
  if (wheelRR >= 0) { sum += wheelRR; validWheels++; }
  if (validWheels > 0) derivedSpeed = sum / validWheels;
  else if (ecmVehSpeed >= 0) derivedSpeed = ecmVehSpeed;
  else if (ecmEngSpeed >= 0) derivedSpeed = ecmEngSpeed * 0.02;
  else derivedSpeed = 0;
  derivedSpeed = (derivedSpeed > 260) ? 260 : (derivedSpeed < 0 ? 0 : derivedSpeed);
  gwMsg.GWS_Vehicle_Speed = derivedSpeed;
  output(gwMsg);
  setTimer(gwTxTimer, 100);
}

/* REQ: GW-REQ-06 */
variables
{
  message GW_System_Overview msgGW;
  int hazardActive = 0; int parkingLamp = 0; int turnCommand = 0;
  msTimer txTimer;
}

on start
{
  // Initialize message payload to safe state
  int i;
  for (i = 0; i < 8; i++)
  {
    msgGW.byte(i) = 0;
  }
  msgGW.dlc = 8;
  msgGW.GWS_Any_Light_On = 0;
  msgGW.GWS_Indicator_State = 0;
  setTimer(txTimer, 100);
}

on message BCM_Body_State
{
  hazardActive = this.Bdy_Hazard_Active;
  parkingLamp  = this.Bdy_Parking_Lamp;
  updateExteriorLightState();
}

on message IC_Driver_Command
{
  turnCommand = this.IC_Turn_Command;
  updateExteriorLightState();
}

void updateExteriorLightState()
{
  int anyLight = 0; int indicatorState = 0;
  if (hazardActive == 1 || turnCommand == 3) { indicatorState = 3; anyLight = 1; }
  else if (turnCommand == 1) { indicatorState = 1; anyLight = 1; }
  else if (turnCommand == 2) { indicatorState = 2; anyLight = 1; }
  if (parkingLamp == 1) anyLight = 1;
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    msgGW.byte(i) = 0;
  }
  msgGW.dlc = 8;
  msgGW.GWS_Any_Light_On = anyLight;
  msgGW.GWS_Indicator_State = indicatorState;
  output(msgGW);
}

on timer txTimer
{
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    msgGW.byte(i) = 0;
  }
  msgGW.dlc = 8;
  output(msgGW);
  setTimer(txTimer, 100);
}

/* REQ: GW-REQ-07 */
variables
{
  msTimer gwTxTimer;
  int currentGear = 0;
}

on start
{
  setTimer(gwTxTimer, 100);
}

on message TCM_Gear_Status
{
  currentGear = this.TCM_Current_Gear;
}

on timer gwTxTimer
{
  message GW_System_Overview msg;
  msg.GWS_Gear_Position = currentGear;
  output(msg);
  setTimer(gwTxTimer, 100);
}
